	css`.BA__packSelect {
    display: flex;
    justify-content: space-between;
    align-items: center;
    cursor: pointer;
    border-radius: 8px;
    background-color: var(--background-base-lowest);
    box-shadow: 0 0 0 1px var(--border-subtle);
    transition: background-color .2s;
    min-height: 84px;
    overflow: hidden;
}
.BA__packSelect:hover {
    background-color: var(--background-base-lower);
}
.BA__packSelectPlaceholder {
    padding-left: 16px;
}

.BA__packSelectPopout {
    display: flex;
    flex-direction: column;
    max-height: 360px;
    border-radius: 8px;
    background-color: var(--background-base-lowest);
    box-shadow: 0 0 0 1px var(--border-subtle),
        var(--shadow-high);
    overflow: hidden;
}
.BA__packSelectPopoutHeader {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 12px;
    border-bottom: 1px solid var(--border-subtle);
}
.BA__packSelectPopoutScroller {
    overflow: hidden auto;
}

.BA__packSelectOption {
    display: flex;
    justify-content: space-between;
    align-items: stretch;
    cursor: pointer;
    background-color: var(--background-base-lowest);
    transition: background-color .2s;
}
.BA__packSelectOption:is(:hover, :focus-visible),
.BA__packSelectOption--focused {
    background-color: var(--background-base-lower);
}
.BA__packSelectOption--selected {
    background-color: var(--background-base-low) !important;
}

.BA__packSelectContent {
    height: 84px;
    display: flex;
    align-items: stretch;
}
.BA__packSelectContentContainer {
    padding: 12px;
    display: flex;
    flex-direction: column;
    justify-content: center;
}
.BA__packSelectContentDescription {
    margin-top: 2px;
    word-break: break-word;
}

.BA__packSelectTrailing {
    display: flex;
    justify-content: flex-end;
    align-items: center;
    box-sizing: content-box;
    width: 24px;
    padding-left: 12px;
    padding-right: 16px;
    flex-shrink: 0;
}

.BA__packSelectActiveDot {
    width: 12px;
    height: 12px;
    border-radius: 50%;
    background-color: var(--brand-500);
}``PackSelect`;
